  1→import React, { useState } from 'react';
  2→import { useQuery } from '@tanstack/react-query';
  3→import { motion, AnimatePresence } from 'framer-motion';
  4→import { getWeeklyRecap, getTodaysPrompt, getPromptResponses } from '../../../API/Api';
  5→import { useAuth } from '../../Context/useAuth';
  6→import useStreakData from '../Streak/useStreakData';
  7→import StreakBadge from '../Streak/StreakBadge';
  8→import RecapSection from './RecapSection';
  9→import PromptSection from './PromptSection';
 10→import './DashboardBriefing.css';
 11→
 12→const getWeekKey = () => {
 13→    const now = new Date();
 14→    const day = now.getUTCDay();
 15→    const diff = day === 0 ? 6 : day - 1;
 16→    const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
 17→    return `recap-dismissed-${monday.toISOString().slice(0, 10)}`;
 18→};
 19→
 20→const formatDate = () => {
 21→    return new Date().toLocaleDateString('en-US', {
 22→        weekday: 'long',
 23→        month: 'long',
 24→        day: 'numeric',
 25→    });
 26→};
 27→
 28→const DashboardBriefing = ({ onWriteResponse }) => {
 29→    const { session, user } = useAuth();
 30→    const weekKey = getWeekKey();
 31→
 32→    const [recapDismissed, setRecapDismissed] = useState(() => {
 33→        try { return localStorage.getItem(weekKey) === 'true'; }
 34→        catch { return false; }
 35→    });
 36→
 37→    // ─── Data fetching ───
 38→
 39→    const { data: recapData, isLoading: recapLoading } = useQuery({
 40→        queryKey: ['weeklyRecap', session?.access_token],
 41→        queryFn: () => getWeeklyRecap(session?.access_token),
 42→        enabled: !!session?.access_token && !recapDismissed,
 43→        staleTime: 1000 * 60 * 10,
 44→        refetchOnWindowFocus: false,
 45→    });
 46→
 47→    const { data: prompt, isLoading: promptLoading } = useQuery({
 48→        queryKey: ['todaysPrompt'],
 49→        queryFn: getTodaysPrompt,
 50→        staleTime: 1000 * 60 * 30,
 51→        refetchOnWindowFocus: false,
 52→    });
 53→
 54→    const { data: responsesData } = useQuery({
 55→        queryKey: ['promptResponses', prompt?.id],
 56→        queryFn: () => getPromptResponses(prompt.id),
 57→        enabled: !!prompt?.id,
 58→        staleTime: 1000 * 60 * 5,
 59→        refetchOnWindowFocus: false,
 60→    });
 61→
 62→    const { data: streakData } = useStreakData(user?.id);
 63→
 64→    // ─── Derived state ───
 65→
 66→    const recap = recapData?.recap;
 67→    const personal = recap?.personal || {};
 68→    const group = recap?.group || {};
 69→
 70→    const hasRecap = !recapDismissed && !recapLoading && recap &&
 71→        (personal.posts_written > 0 || group.total_posts > 0);
 72→    const hasPrompt = !promptLoading && !!prompt;
 73→
 74→    // Nothing to show
 75→    if (!hasRecap && !hasPrompt) return null;
 76→
 77→    const handleDismissRecap = (e) => {
 78→        e.stopPropagation();
 79→        try { localStorage.setItem(weekKey, 'true'); }
 80→        catch { /* no-op */ }
 81→        setRecapDismissed(true);
 82→    };
 83→
 84→    const streakCount = streakData?.current_streak || 0;
 85→
 86→    return (
 87→        <AnimatePresence>
 88→            <motion.div
 89→                className="dashboard-briefing"
 90→                initial={{ opacity: 0, y: -10 }}
 91→                animate={{ opacity: 1, y: 0 }}
 92→                exit={{ opacity: 0, y: -15, transition: { duration: 0.25 } }}
 93→                transition={{ duration: 0.35, ease: 'easeOut' }}
 94→                key="dashboard-briefing"
 95→            >
 96→                <div className="dashboard-briefing-header">
 97→                    <div className="dashboard-briefing-header-left">
 98→                        <span className="dashboard-briefing-title">Today</span>
 99→                        <span className="dashboard-briefing-date">{formatDate()}</span>
100→                        {streakCount > 0 && <StreakBadge count={streakCount} size={14} />}
101→                    </div>
102→                    {hasRecap && (
103→                        <button
104→                            className="dashboard-briefing-dismiss"
105→                            onClick={handleDismissRecap}
106→                            title="Dismiss recap"
107→                        >
108→                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
109→                                <path d="M18 6L6 18M6 6L18 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
110→                            </svg>
111→                        </button>
112→                    )}
113→                </div>
114→
115→                <div className="dashboard-briefing-body">
116→                    {hasRecap && (
117→                        <RecapSection personal={personal} group={group} />
118→                    )}
119→
120→                    {hasRecap && hasPrompt && (
121→                        <div className="dashboard-divider" />
122→                    )}
123→
124→                    {hasPrompt && (
125→                        <PromptSection
126→                            prompt={prompt}
127→                            responsesData={responsesData}
128→                            onWriteResponse={onWriteResponse}
129→                        />
130→                    )}
131→                </div>
132→            </motion.div>
133→        </AnimatePresence>
134→    );
135→};
136→
137→export default DashboardBriefing;
138→

 1→import React from 'react';
 2→
 3→const PromptSection = ({ prompt, responsesData, onWriteResponse }) => {
 4→    const responseCount = responsesData?.count || 0;
 5→    const avatars = (responsesData?.responses || []).slice(0, 5);
 6→
 7→    return (
 8→        <div className="dashboard-prompt">
 9→            <div className="dashboard-prompt-header">
10→                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 -960 960 960" fill="currentColor" className="dashboard-prompt-icon">
11→                    <path d="M480-80q-26 0-47-12.5T400-126q-33 0-56.5-23.5T320-206v-142q-59-39-94.5-103T190-590q0-121 84.5-205.5T480-880q121 0 205.5 84.5T770-590q0 77-35.5 140T640-348v142q0 33-23.5 56.5T560-126q-12 21-33 33.5T480-80Zm-80-126h160v-36H400v36Zm0-76h160v-38H400v38Zm-8-118h58v-108l-88-88 42-42 76 76 76-76 42 42-88 88v108h58q54-26 88-76.5T690-590q0-88-61-149t-149-61q-88 0-149 61t-61 149q0 63 34 113.5t88 76.5Z"/>
12→                </svg>
13→                <span className="dashboard-prompt-label">Today's Prompt</span>
14→                {prompt.category && (
15→                    <span className="dashboard-prompt-category">{prompt.category}</span>
16→                )}
17→            </div>
18→            <p className="dashboard-prompt-text">{prompt.prompt_text}</p>
19→            <div className="dashboard-prompt-footer">
20→                <button
21→                    className="dashboard-prompt-write-btn"
22→                    onClick={() => onWriteResponse?.(prompt)}
23→                >
24→                    Write your take <span style={{ marginLeft: '6px' }}>→</span>
25→                </button>
26→                {responseCount > 0 && (
27→                    <div className="dashboard-prompt-responses">
28→                        <div className="dashboard-prompt-avatars">
29→                            {avatars.map((r, i) => (
30→                                <img
31→                                    key={r.id}
32→                                    src={r.users?.image_url || '/assets/profile.jpg'}
33→                                    alt=""
34→                                    className="dashboard-prompt-avatar"
35→                                    style={{ zIndex: avatars.length - i }}
36→                                />
37→                            ))}
38→                        </div>
39→                        <span className="dashboard-prompt-count">
40→                            {responseCount} {responseCount === 1 ? 'response' : 'responses'}
41→                        </span>
42→                    </div>
43→                )}
44→            </div>
45→        </div>
46→    );
47→};
48→
49→export default PromptSection;
