  6→    border-left: 3px solid var(--accent-amber);
  7→    border-radius: 14px;
  8→    box-shadow: var(--shadow-card-sm);
  9→    width: 100%;
 10→    margin-bottom: 16px;
 11→    overflow: hidden;
 12→}
