132→    margin-top: 8px;
133→    border-top: 1px solid var(--border-card);
134→    display: flex;
135→    flex-direction: column;
136→    gap: 10px;
137→}
138→
139→.dashboard-recap-detail {
140→    display: flex;
141→    flex-direction: column;
142→    gap: 3px;
143→}
144→
145→.dashboard-recap-detail-heading {
146→    font-family: 'Outfit', sans-serif;
147→    font-size: 11px;
148→    font-weight: 600;
149→    text-transform: uppercase;
150→    letter-spacing: 0.3px;
151→    color: var(--text-secondary, #a1a1aa);
