181→}
182→
183→.dashboard-prompt-header {
184→    display: flex;
185→    align-items: center;
186→    gap: 8px;
187→}
188→
189→.dashboard-prompt-icon {
190→    opacity: 0.7;
191→    color: var(--accent-amber, #f59e0b);
192→    flex-shrink: 0;
193→}
194→
195→.dashboard-prompt-label {
196→    font-family: 'Outfit', sans-serif;
