276→    object-fit: cover;
277→}
278→
279→.dashboard-prompt-avatar:first-child {
280→    margin-left: 0;
281→}
282→
283→.dashboard-prompt-count {
284→    font-size: 12px;
285→    color: var(--text-secondary, #a1a1aa);
286→}
287→
288→/* ─── Mobile ─── */
289→
290→@media (max-width: 480px) {
291→    .dashboard-briefing-body {
292→        padding: 12px 16px 14px;
293→    }
294→
295→    .dashboard-briefing-header {
296→        padding: 12px 16px 0;
297→    }
298→
299→    .dashboard-prompt-text {
300→        font-size: 15px;
301→    }
302→}
303→
304→/* ─── Dark mode ─── */
