 4→const useStreakData = (userId) => {
 5→    return useQuery({
 6→        queryKey: ['streak', userId],
 7→        queryFn: () => getStreak(userId),
 8→        enabled: !!userId,
 9→        staleTime: 1000 * 60 * 5,
10→        refetchOnWindowFocus: false,
11→    });
12→};
13→
14→export default useStreakData;
