        <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z"/><circle cx="12" cy="12" r="3"/>
    </svg>
);

const RecapSection = ({ personal, group, streakCount = 0 }) => {
    const encouragement = getOverallEncouragement(personal, streakCount);

    return (
        <div className="dashboard-recap-v2">
            {/* Overall encouragement line */}
            <motion.p
                className="recap-encouragement"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.4, delay: 0.05 }}
            >
                {encouragement}
            </motion.p>

            {/* 4 stat tiles in a row */}
            <div className="recap-tiles-grid">
                <StatTile
                    icon={<PenIcon />}
                    value={personal?.posts_written || 0}
                    label="posts"
                    microCopy={getPostsCopy(personal?.posts_written || 0)}
                    index={0}
                />
                <StatTile
                    icon={<TypeIcon />}
                    value={personal?.total_words || 0}
                    label="words"
                    microCopy={getWordsCopy(personal?.total_words || 0)}
                    index={1}
                />
                <StatTile
                    icon={<HeartIcon />}
                    value={personal?.reactions_received || 0}
                    label="reactions"
                    microCopy={getReactionsCopy(personal?.reactions_received || 0)}
                    index={2}
                />
                <StatTile
                    icon={<EyeIcon />}
                    value={personal?.views_received || 0}
                    label="views"
                    microCopy={getViewsCopy(personal?.views_received || 0)}
                    index={3}
                />
            </div>

            {/* Best post achievement card */}
            <BestPostCard bestPost={personal?.best_post} />

            {/* Community highlights (always visible) */}
            <CommunityHighlights group={group} />
        </div>
    );
};

export default RecapSection;
